def _download_workbook_bytes() -> bytes:
    """Descarga el XLSX completo una sola vez y devuelve los bytes en memoria."""
    req = urllib.request.Request(BASE_URL, headers={"User-Agent": "Mozilla/5.0"})
    with urllib.request.urlopen(req, timeout=60) as resp:
        return resp.read()


def load_all_sheets(sheet_names: list[str]) -> dict[str, pd.DataFrame]:
    """
    Descarga el XLSX una única vez y lee todas las hojas en paralelo.
    Devuelve un dict {sheet_name: DataFrame}.
    """
    print("[INFO] Descargando workbook (una sola petición)...")
    try:
        raw_bytes = _download_workbook_bytes()
    except Exception as e:
        print(f"[ERROR] No se pudo descargar el workbook: {e}")
        return {name: pd.DataFrame() for name in sheet_names}

    def _read_sheet(name: str) -> tuple[str, pd.DataFrame]:
        try:
            df = pd.read_excel(
                io.BytesIO(raw_bytes),
                sheet_name=name,
                engine="openpyxl",
            )
            df.columns = [str(c).strip() for c in df.columns]
            print(f"[INFO] Hoja '{name}': {len(df)} filas leídas")
            return name, df
        except Exception as e:
            print(f"[ERROR] Hoja '{name}': {e}")
            return name, pd.DataFrame()

    with ThreadPoolExecutor(max_workers=len(sheet_names)) as pool:
        results = pool.map(_read_sheet, sheet_names)

    return dict(results)


def load_sheet(sheet_name: str) -> pd.DataFrame:
    """Compatibilidad: descarga solo la hoja solicitada (uso individual)."""
    return load_all_sheets([sheet_name]).get(sheet_name, pd.DataFrame())


def process_orders(raw: pd.DataFrame) -> pd.DataFrame:
    df = raw.copy()
    date_cols = ["FECHA / HORA CREACIÓN", "FECHA / HORA INICIO TRABAJO",
                 "FECHA / HORA FIN TRABAJO", "FECHA / HORA ENTREGA"]
    for col in date_cols:
        if col in df.columns:
            df[col] = pd.to_datetime(df[col], errors="coerce", dayfirst=True)
    if "OT_ID" in df.columns:
        df["OT_ID"] = pd.to_numeric(df["OT_ID"], errors="coerce")
    if {"FECHA / HORA FIN TRABAJO", "FECHA / HORA INICIO TRABAJO"}.issubset(df.columns):
        df["DURACION_DIAS"] = (
            (df["FECHA / HORA FIN TRABAJO"] - df["FECHA / HORA INICIO TRABAJO"])
            .dt.total_seconds() / 86400
        ).clip(lower=0)
    else:
        df["DURACION_DIAS"] = pd.NA
    if "FECHA / HORA CREACIÓN" in df.columns:
        df["SEMANA"]     = df["FECHA / HORA CREACIÓN"].dt.to_period("W").astype(str)
        df["DIA_SEMANA"] = df["FECHA / HORA CREACIÓN"].dt.day_name()
        df["HORA"]       = df["FECHA / HORA CREACIÓN"].dt.hour
    if "TECNICO ASIGNADO NOMBRE" in df.columns:
        df["TECNICO_PRINCIPAL"] = (
            df["TECNICO ASIGNADO NOMBRE"].astype(str)
            .str.split(",").str[0].str.strip().str.title()
        )
    if "ESTADO DE ORDEN" in df.columns:
        import unicodedata as _ud
        # Tabla de normalización: versiones sin tilde → forma canónica con tilde
        _ESTADO_MAP = {
            "DIAGNOSTICO":       "DIAGNÓSTICO",
            "DIAGN\u00d3STICO":  "DIAGNÓSTICO",    # ya correcto, por si acaso
            "EN APROBACION":     "EN APROBACIÓN",
            "NO APROBADO":       "NO APROBADO",
            "EN IMPORTACION":    "EN IMPORTACIÓN",
            "EN IMPORTACIÓN": "EN IMPORTACIÓN",
            "DE BAJA":           "DE BAJA",
            "EN EJECUCION":      "EN EJECUCIÓN",
            "FACTURACION":       "FACTURADO",
            "EN PROCESO":        "EN EJECUCIÓN",    # alias legado → nuevo nombre
        }
        def _norm_estado(val):
            s = str(val).strip().upper()
            # Intentar directamente en el mapa
            if s in _ESTADO_MAP:
                return _ESTADO_MAP[s]
            # Quitar acentos y buscar en mapa
            s_sin = _ud.normalize("NFD", s)
            s_sin = "".join(c for c in s_sin if _ud.category(c) != "Mn")
            return _ESTADO_MAP.get(s_sin, s)
        df["ESTADO_ORDEN"] = df["ESTADO DE ORDEN"].apply(_norm_estado)
    if {"FECHA / HORA INICIO TRABAJO", "FECHA / HORA CREACIÓN"}.issubset(df.columns):
        df["LEAD_TIME_H"] = (
            (df["FECHA / HORA INICIO TRABAJO"] - df["FECHA / HORA CREACIÓN"])
            .dt.total_seconds() / 3600
        ).clip(lower=0)
    return df


def process_details(raw: pd.DataFrame) -> pd.DataFrame:
    df = raw.copy().replace("", pd.NA)
    if "OT_ID" not in df.columns:
        return pd.DataFrame()
    df["OT_ID"] = pd.to_numeric(df["OT_ID"], errors="coerce")
    df = df[df["OT_ID"].notna()].copy()
    df["OT_ID"] = df["OT_ID"].astype(int)
    if "MARCA" in df.columns:
        df["MARCA"] = df["MARCA"].astype(str).str.strip().str.upper()
    if "CANT" in df.columns:
        df["CANT"] = pd.to_numeric(df["CANT"], errors="coerce").fillna(1)
    return df


