def _load_drive_index():
    candidates = [
        os.path.join(os.path.dirname(os.path.abspath(__file__)), "ordenes_drive_index.json"),
        "ordenes_drive_index.json",
    ]
    for p in candidates:
        if os.path.exists(p):
            try:
                import json as _json
                with open(p, encoding="utf-8") as f:
                    return {str(k): str(v) for k, v in _json.load(f).items()}
            except Exception as e:
                print(f"[WARN] No se pudo leer ordenes_drive_index.json: {e}")
    return {}

