# PRE-CARGA EN BACKGROUND
# Inicia la descarga de Google Sheets en un hilo separado apenas
# arranca el servidor, para que los datos estén listos cuando el
# usuario termine de loguearse.
# ══════════════════════════════════════════════════════════════════
_preload_done  = threading.Event()   # señal: precarga terminada
_preload_error = None                # guarda excepción si falla

def _background_preload():
    global _preload_error
    try:
        print("[INFO] Pre-carga background iniciada...")
        reload_data()
        print(f"[INFO] Pre-carga completada: {len(DF_BASE)} órdenes · {len(DET_BASE)} equipos")
    except Exception as e:
        _preload_error = e
        print(f"[WARN] Pre-carga falló: {e}")
    finally:
        _preload_done.set()

_preload_thread = threading.Thread(target=_background_preload, daemon=True)
_preload_thread.start()


def reload_data():
    global DF_BASE, DET_BASE, CUST_BASE

    # ── UNA sola descarga para las tres hojas ─────────────────────
    sheets = load_all_sheets(["OrderHeader", "OrderDetails", "Customer"])
    DF_BASE   = process_orders(sheets.get("OrderHeader", pd.DataFrame()))
    DET_BASE  = process_details(sheets.get("OrderDetails", pd.DataFrame()))
    CUST_BASE = sheets.get("Customer", pd.DataFrame())

    # ── CIUDAD: leer directamente de OrderHeader si existe ────────
    if "CIUDAD" in DF_BASE.columns:
        DF_BASE["CIUDAD_CLIENTE"] = (
            DF_BASE["CIUDAD"].astype(str).str.strip().str.upper()
            .replace({"NAN": pd.NA, "": pd.NA, ".": pd.NA})
        )
    else:
        DF_BASE["CIUDAD_CLIENTE"] = pd.NA

    # ── PROVINCIA_GEO: nombre exacto del GeoJSON para el mapa ────
    # Prioridad 1: columna PROVINCIA en OrderHeader (si el GSheet la tiene)
    # Prioridad 2: mapeo desde CIUDAD
    def _get_prov_geo(row):
        # Intentar desde columna PROVINCIA del OrderHeader
        if "PROVINCIA" in row.index:
            p = str(row["PROVINCIA"]).strip().upper()
            if p and p not in ("NAN", "", "RUTA STANDARD"):
                geo_name = PROV_TO_GEO.get(p)
                if geo_name:
                    return geo_name
        # Fallback: desde columna CIUDAD
        ciudad = str(row.get("CIUDAD_CLIENTE", "")).strip().upper()
        return CIUDAD_TO_GEO_PROV.get(ciudad)
    DF_BASE["PROVINCIA_GEO"] = DF_BASE.apply(_get_prov_geo, axis=1)

    # ── NOMBRE PRINCIPAL: join con Customer para nombre cliente ───
    if not CUST_BASE.empty:
        CUST_BASE["Customer_ID"] = pd.to_numeric(CUST_BASE["Customer_ID"], errors="coerce")
        _nc = pd.to_numeric(DF_BASE.get("NOMBRE CLIENTE", pd.Series(dtype=float)),
                            errors="coerce")
        DF_BASE["_cust_id"] = _nc.values
        _cust_cols = [c for c in ["Customer_ID", "NOMBRE PRINCIPAL", "PROVINCIA"]
                      if c in CUST_BASE.columns]
        _merged = DF_BASE.merge(CUST_BASE[_cust_cols], left_on="_cust_id",
                                right_on="Customer_ID", how="left")
        if "PROVINCIA" in _merged.columns:
            DF_BASE["PROVINCIA_CLIENTE"] = _merged["PROVINCIA"].values
        if "NOMBRE PRINCIPAL" in _merged.columns:
            DF_BASE["NOMBRE_CLIENTE"] = _merged["NOMBRE PRINCIPAL"].values
        DF_BASE.drop(columns=["_cust_id"], errors="ignore", inplace=True)

    print(f"[INFO] CIUDAD_CLIENTE — {DF_BASE['CIUDAD_CLIENTE'].notna().sum()} registros con ciudad")

DF_BASE   = pd.DataFrame()
DET_BASE  = pd.DataFrame()
CUST_BASE = pd.DataFrame()
print("[INFO] Servidor listo — los datos se cargarán desde el navegador del cliente")

