FILTER_INPUTS = [
    Input("filter-tipo",     "value"),
    Input("filter-estado",   "value"),
    Input("filter-tecnico",  "value"),
    Input("filter-cliente",  "value"),
    Input("filter-fechas",   "start_date"),
    Input("filter-fechas",   "end_date"),
    Input("btn-refresh",     "n_clicks"),
    Input("interval-refresh","n_intervals"),
]


def filter_df(tipo, estado, tecnico, cliente=None, start=None, end=None):
    dff = DF_BASE.copy()
    if tipo and tipo != "Todos" and "TIPO DE ORDEN" in dff.columns:
        dff = dff[dff["TIPO DE ORDEN"] == tipo]
    if estado and estado != "Todos" and "ESTADO_ORDEN" in dff.columns:
        dff = dff[dff["ESTADO_ORDEN"] == estado]
    if tecnico and tecnico != "Todos" and "TECNICO_PRINCIPAL" in dff.columns:
        dff = dff[dff["TECNICO_PRINCIPAL"] == tecnico]
    if cliente and cliente != "Todos" and "NOMBRE_CLIENTE" in dff.columns:
        dff = dff[dff["NOMBRE_CLIENTE"] == cliente]
    if start and end and "FECHA / HORA CREACIÓN" in dff.columns:
        dff = dff[
            (dff["FECHA / HORA CREACIÓN"].dt.date >= pd.to_datetime(start).date()) &
            (dff["FECHA / HORA CREACIÓN"].dt.date <= pd.to_datetime(end).date())
        ]
    return dff


def filter_det(dff):
    if DET_BASE.empty or "OT_ID" not in dff.columns:
        return pd.DataFrame()
    return DET_BASE[DET_BASE["OT_ID"].isin(dff["OT_ID"])]

# ══════════════════════════════════════════════════════════════════
# CALLBACK: CARGA INICIAL LAZY
# Se dispara en el primer tick del interval (browser ya cargó la página).
# Primera vez: descarga datos de Google Sheets y muestra el dashboard.
# Veces siguientes: recarga silenciosa cada 5 min.
# ══════════════════════════════════════════════════════════════════

@app.callback(
    Output("loading-screen",    "style"),
    Output("dashboard-content", "style"),
    Output("data-loaded-store", "data"),
    Output("filter-tipo",    "options", allow_duplicate=True),
    Output("filter-estado",  "options", allow_duplicate=True),
    Output("filter-tecnico", "options", allow_duplicate=True),
    Output("filter-cliente", "options", allow_duplicate=True),
    Output("filter-fechas",  "min_date_allowed", allow_duplicate=True),
    Output("filter-fechas",  "max_date_allowed", allow_duplicate=True),
    Input("login-success-store", "data"),
    Input("interval-refresh",    "n_intervals"),
    State("data-loaded-store",   "data"),
    prevent_initial_call="initial_duplicate",
)
def initial_data_load(login_success, n_intervals, already_loaded):
    from dash import ctx
    triggered = ctx.triggered_id if ctx.triggered_id else ""

    if triggered == "login-success-store":
        # Login acaba de ocurrir: si la precarga background terminó, los datos
        # ya están en memoria; si no, esperar hasta 8 s antes de recargar.
        if not _preload_done.is_set():
            _preload_done.wait(timeout=8)
        if DF_BASE.empty:
            # Precarga falló o aún no completó — forzar carga sincrónica
            try:
                reload_data()
            except Exception as e:
                print(f"[ERROR] reload_data en login: {e}")
        else:
            print(f"[INFO] Login — datos ya en memoria: {len(DF_BASE)} órdenes")
    else:
        # Intervalo de auto-refresh: siempre recargar
        try:
            reload_data()
            status = "recarga" if already_loaded else "inicial"
            print(f"[INFO] Carga {status}: {len(DF_BASE)} órdenes · {len(DET_BASE)} equipos")
        except Exception as e:
            print(f"[ERROR] reload_data: {e}")

    tipos    = ["Todos"] + sorted(DF_BASE["TIPO DE ORDEN"].dropna().unique().tolist()) \
        if "TIPO DE ORDEN" in DF_BASE.columns else ["Todos"]
    estados  = ["Todos"] + sorted(DF_BASE["ESTADO_ORDEN"].dropna().unique().tolist()) \
        if "ESTADO_ORDEN" in DF_BASE.columns else ["Todos"]
    tecnicos = ["Todos"] + sorted(
        t for t in DF_BASE["TECNICO_PRINCIPAL"].dropna().unique()
        if t not in ("Nan", "nan")
    ) if "TECNICO_PRINCIPAL" in DF_BASE.columns else ["Todos"]
    clientes = ["Todos"] + sorted(
        str(c) for c in DF_BASE["NOMBRE_CLIENTE"].dropna().unique()
        if str(c) not in ("nan", "")
    ) if "NOMBRE_CLIENTE" in DF_BASE.columns else ["Todos"]
    fmin = DF_BASE["FECHA / HORA CREACIÓN"].min().date().isoformat() \
        if "FECHA / HORA CREACIÓN" in DF_BASE.columns \
        and DF_BASE["FECHA / HORA CREACIÓN"].notna().any() else "2026-01-01"
    fmax = DF_BASE["FECHA / HORA CREACIÓN"].max().date().isoformat() \
        if "FECHA / HORA CREACIÓN" in DF_BASE.columns \
        and DF_BASE["FECHA / HORA CREACIÓN"].notna().any() else "2026-12-31"
    opt = lambda lst: [{"label": v, "value": v} for v in lst]

    return (
        {"display": "none"},   # ocultar loading-screen
        {"display": "block"},  # mostrar dashboard-content
        True,
        opt(tipos), opt(estados), opt(tecnicos), opt(clientes),
        fmin, fmax,
    )


# ══════════════════════════════════════════════════════════════════
# CALLBACKS
# ══════════════════════════════════════════════════════════════════

@app.callback(
    Output("header-datetime",    "children"),
    Output("header-last-update", "children"),
    Output("filter-tipo",        "options"),
    Output("filter-estado",      "options"),
    Output("filter-tecnico",     "options"),
    Output("filter-cliente",     "options"),
    Output("filter-fechas",      "min_date_allowed"),
    Output("filter-fechas",      "max_date_allowed"),
    Input("interval-refresh",    "n_intervals"),
    Input("btn-refresh",         "n_clicks"),
)
def update_clock_and_filters(n_intervals, n_clicks):
    from datetime import datetime
    from dash import ctx

    # Recargar datos siempre que sea el botón o el primer disparo del intervalo
    triggered = ctx.triggered_id if ctx.triggered_id else ""
    # Solo recarga cuando el usuario presiona el botón manualmente
    # (el interval ya lo maneja el callback initial_data_load)
    if triggered == "btn-refresh" and n_clicks:
        try:
            reload_data()
            print("[INFO] Datos recargados desde Google Sheets")
        except Exception as e:
            print(f"[WARN] reload_data: {e}")

    now   = datetime.now()
    fecha = now.strftime("%A, %d %B %Y  —  %H:%M:%S")
    upd   = f"🔄 Última actualización: {now.strftime('%d/%m/%Y  %H:%M:%S')}"

    # Reconstruir opciones de filtros con datos frescos
    tipos    = ["Todos"] + sorted(DF_BASE["TIPO DE ORDEN"].dropna().unique().tolist())                if "TIPO DE ORDEN" in DF_BASE.columns else ["Todos"]
    estados  = ["Todos"] + sorted(DF_BASE["ESTADO_ORDEN"].dropna().unique().tolist())                if "ESTADO_ORDEN" in DF_BASE.columns else ["Todos"]
    tecnicos = ["Todos"] + sorted(
        t for t in DF_BASE["TECNICO_PRINCIPAL"].dropna().unique()
        if t not in ("Nan", "nan")
    ) if "TECNICO_PRINCIPAL" in DF_BASE.columns else ["Todos"]
    clientes = ["Todos"] + sorted(
        str(c) for c in DF_BASE["NOMBRE_CLIENTE"].dropna().unique()
        if str(c) not in ("nan", "")
    ) if "NOMBRE_CLIENTE" in DF_BASE.columns else ["Todos"]

    fmin = DF_BASE["FECHA / HORA CREACIÓN"].min().date().isoformat()            if "FECHA / HORA CREACIÓN" in DF_BASE.columns and DF_BASE["FECHA / HORA CREACIÓN"].notna().any()            else "2026-01-01"
    fmax = DF_BASE["FECHA / HORA CREACIÓN"].max().date().isoformat()            if "FECHA / HORA CREACIÓN" in DF_BASE.columns and DF_BASE["FECHA / HORA CREACIÓN"].notna().any()            else "2026-12-31"

    opt = lambda lst: [{"label": v, "value": v} for v in lst]
    return fecha, upd, opt(tipos), opt(estados), opt(tecnicos), opt(clientes), fmin, fmax


@app.callback(
    Output("kpi-row-top",    "children"),
    Output("kpi-row-bottom", "children"),
    FILTER_INPUTS,
)
def update_kpis(tipo, estado, tecnico, cliente, start, end, *_):
    dff  = filter_df(tipo, estado, tecnico, cliente, start, end)
    n    = len(dff)

    def _count(est):
        return int((dff["ESTADO_ORDEN"] == est).sum()) if "ESTADO_ORDEN" in dff.columns else 0

    pend  = _count("PENDIENTE")
    diag  = _count("DIAGNÓSTICO")
    apro  = _count("EN APROBACIÓN")
    ejec  = _count("EN EJECUCIÓN")
    fin   = _count("FINALIZADO")
    entr  = _count("ENTREGADO")
    fact  = _count("FACTURADO")

    tasa = round((entr + fin + fact) / n * 100, 1) if n else 0
    dur  = dff["DURACION_DIAS"].dropna().mean() if "DURACION_DIAS" in dff.columns else None
    dur_s = f"{round(dur, 1)}d" if dur and not pd.isna(dur) else "—"

    # ── IAC: órdenes atendidas (FINALIZADO/ENTREGADO/FACTURADO) en ≤30 días / total ──
    objetivo_dias = 30
    iac_val = 0.0
    if "ESTADO_ORDEN" in dff.columns and "FECHA / HORA CREACIÓN" in dff.columns:
        total_sol = len(dff)
        atendidas_df = dff[dff["ESTADO_ORDEN"].isin(ESTADOS_ATENDIDOS)].copy()
        if total_sol > 0 and not atendidas_df.empty:
            fecha_fin_col = (
                "FECHA / HORA ENTREGA" if "FECHA / HORA ENTREGA" in atendidas_df.columns
                else "FECHA / HORA FIN TRABAJO"
            )
            if fecha_fin_col in atendidas_df.columns:
                atendidas_df["tiempo_atencion"] = (
                    atendidas_df[fecha_fin_col] - atendidas_df["FECHA / HORA CREACIÓN"]
                ).dt.total_seconds() / 86400
                # Órdenes atendidas con tiempo válido y dentro del objetivo
                validas = atendidas_df["tiempo_atencion"].dropna()
                dentro  = int((validas >= 0) & (validas <= objetivo_dias)).sum()                           if len(validas) == 0 else int(((validas >= 0) & (validas <= objetivo_dias)).sum())
                iac_val = round((dentro / total_sol) * 100, 1)

    if iac_val >= 95:
        iac_color, iac_icon = C["green"],  "🟢"
    elif iac_val >= 85:
        iac_color, iac_icon = C["teal"],   "🟡"
    elif iac_val >= 70:
        iac_color, iac_icon = C["orange"], "🟠"
    else:
        iac_color, iac_icon = C["red"],    "🔴"

    top = [
        kpi_card(n,    "Total Órdenes",  C["blue"],      "📋"),
        kpi_card(pend, "Pendiente",      C["orange"],    "⏳"),
        kpi_card(diag, "Diagnóstico",    C["teal"],      "🔍"),
        kpi_card(apro, "En Aprobación",  C["yellow"],    "📝"),
        kpi_card(ejec, "En Ejecución",   C["blue"],      "🔨"),
        kpi_card(fin,  "Finalizado",     C["purple"],    "✔️"),
        kpi_card(entr, "Entregado",      C["green"],     "📦"),
        kpi_card(fact, "Facturado",      C["blue_dark"], "🧾"),
    ]
    bottom = [
        kpi_card(f"{tasa}%",    "Tasa Completadas",      C["green"],   "✅"),
        kpi_card(dur_s,         "Días Promedio",          C["purple"],  "⏱️"),
        kpi_card(f"{iac_val}%", "IAC — Índice Atención", iac_color,    iac_icon),
    ]
    return top, bottom


