@app.callback(Output("fig-equipos", "figure"), FILTER_INPUTS)
def fig_equipos(tipo, estado, tecnico, cliente, start, end, *_):
    dff  = filter_df(tipo, estado, tecnico, cliente, start, end)
    detf = filter_det(dff)
