@app.callback(Output("fig-iac-mensual", "figure"), FILTER_INPUTS)
def fig_iac_mensual(tipo, estado, tecnico, cliente, start, end, *_):
    dff = filter_df(tipo, estado, tecnico, cliente, start, end)
    objetivo_dias = 30
    fecha_fin_col = "FECHA / HORA ENTREGA" if "FECHA / HORA ENTREGA" in dff.columns else "FECHA / HORA FIN TRABAJO"

    if "FECHA / HORA CREACIÓN" not in dff.columns or dff.empty:
        return empty_fig()

    # Crear columna MES con formato "Mmm-AA"
    dff = dff.copy()
    dff["MES_PERIOD"] = dff["FECHA / HORA CREACIÓN"].dt.to_period("M")
    dff["MES_LABEL"]  = dff["FECHA / HORA CREACIÓN"].dt.strftime("%b%y").str.upper()

    rows = []
    for mes_period, grp in dff.groupby("MES_PERIOD"):
        total = len(grp)           # denominador: todas las órdenes del mes
        if total == 0:
            continue
        mes_label = grp["MES_LABEL"].iloc[0]

        # Numerador: solo órdenes en estado FINALIZADO / ENTREGADO / FACTURADO
        atendidas = grp[grp["ESTADO_ORDEN"].isin(ESTADOS_ATENDIDOS)].copy()                     if "ESTADO_ORDEN" in grp.columns else pd.DataFrame()

        dentro = 0
        if not atendidas.empty and fecha_fin_col in atendidas.columns                 and "FECHA / HORA CREACIÓN" in atendidas.columns:
            atendidas["tiempo"] = (
                atendidas[fecha_fin_col] - atendidas["FECHA / HORA CREACIÓN"]
            ).dt.total_seconds() / 86400
            tiempos_validos = atendidas["tiempo"].dropna()
            dentro = int(((tiempos_validos >= 0) & (tiempos_validos <= objetivo_dias)).sum())

        iac = round((dentro / total) * 100, 1)
        rows.append({"Mes": mes_label, "MES_P": mes_period, "IAC": iac,
                     "Atendidos": int(dentro),
                     "TotalAtendidas": len(atendidas),
                     "Total": total})

    if not rows:
        return empty_fig("Sin datos suficientes para calcular IAC mensual")

    df_iac = pd.DataFrame(rows).sort_values("MES_P")

    # Color de cada barra según benchmark
    bar_colors = []
    for v in df_iac["IAC"]:
        if v >= 95:   bar_colors.append(C["green"])
        elif v >= 85: bar_colors.append(C["teal"])
        elif v >= 70: bar_colors.append(C["orange"])
        else:         bar_colors.append(C["red"])

    fig = go.Figure()

    # Zonas de fondo
    fig.add_hrect(y0=0,   y1=70,  fillcolor="#FDECEA", opacity=0.18, line_width=0)
    fig.add_hrect(y0=70,  y1=85,  fillcolor="#FFF3E0", opacity=0.18, line_width=0)
    fig.add_hrect(y0=85,  y1=95,  fillcolor="#FFF9C4", opacity=0.18, line_width=0)
    fig.add_hrect(y0=95,  y1=105, fillcolor="#E8F5E9", opacity=0.18, line_width=0)

    # Barras IAC mensual
    fig.add_trace(go.Bar(
        x=df_iac["Mes"], y=df_iac["IAC"],
        marker=dict(color=bar_colors, line=dict(color="white", width=1.5),
                    opacity=0.88),
        text=[f"<b>{v}%</b>" for v in df_iac["IAC"]],
        textposition="outside",
        textfont=dict(size=13, family="Segoe UI, sans-serif"),
        customdata=list(zip(df_iac["Atendidos"], df_iac["TotalAtendidas"], df_iac["Total"])),
        hovertemplate=(
            "<b>%{x}</b><br>"
            "IAC: <b>%{y:.1f}%</b><br>"
            "─────────────────────<br>"
            "✔ En tiempo (≤30d): %{customdata[0]}<br>"
            "📦 Total atendidas: %{customdata[1]}<br>"
            "📋 Total del mes:   %{customdata[2]}<br>"
            "Estados: Finalizado · Entregado · Facturado<extra></extra>"
        ),
        name="IAC Mensual",
    ))

    # Líneas de benchmark (discontinuas, colores distintos)
    benchmarks = [
        (70,  "🔴 Deficiente < 70%",    "#D13438", "dash"),
        (85,  "🟠 Aceptable 70–85%",    "#F7630C", "dot"),
        (95,  "🟡 Bueno 85–95%",        "#F2C811", "dashdot"),
        (100, "🟢 Clase Mundial > 95%", "#107C10", "longdash"),
    ]
    for y_val, lbl, col, dash in benchmarks:
        fig.add_hline(
            y=y_val, line_dash=dash, line_color=col, line_width=2,
            annotation_text=f"  {lbl}",
            annotation_position="top right",
            annotation_font=dict(size=10, color=col, family="Segoe UI, sans-serif"),
        )

    fig.update_layout(
        yaxis=dict(range=[0, 112], ticksuffix="%", tickfont=dict(size=13),
                   gridcolor="#F0F0F0"),
        xaxis=dict(tickfont=dict(size=13)),
        xaxis_title="", yaxis_title="IAC (%)",
        showlegend=False,
        bargap=0.35,
    )
    return apply_theme(fig)

@app.callback(
    Output("tabla-activas", "children"),
    FILTER_INPUTS + [
        Input("tbl-filter-ot",          "value"),
        Input("tbl-filter-tipo-col",    "value"),
        Input("tbl-filter-estado-col",  "value"),
        Input("tbl-filter-tecnico-col", "value"),
    ]
)
def update_tabla(tipo, estado, tecnico, cliente, start, end, *args):
    from datetime import datetime
    # args[-4:] = filtros de columna
    f_ot, f_tipo_col, f_estado_col, f_tecnico_col = (args[-4] or ""), (args[-3] or ""), (args[-2] or ""), (args[-1] or "")
    dff = filter_df(tipo, estado, tecnico, cliente, start, end)
    if "ESTADO_ORDEN" not in dff.columns:
        return html.Div("Sin datos", style={"color": C["gray"], "fontSize": "14px"})

    # Mostrar todos los estados, ordenados
    orden_estado = {"PENDIENTE": 0, "DIAGNÓSTICO": 1, "EN APROBACIÓN": 2, "EN EJECUCIÓN": 3, "FINALIZADO": 4, "ENTREGADO": 5, "FACTURADO": 6}
    activas = dff.copy()
    activas["_ord"] = activas["ESTADO_ORDEN"].map(orden_estado).fillna(99)
    activas = activas.sort_values("_ord").drop(columns=["_ord"])

    # ── Aplicar filtros de columna ──────────────────────────────
    if f_ot.strip() and "OT_ID" in activas.columns:
        activas = activas[activas["OT_ID"].astype(str).str.contains(f_ot.strip(), case=False, na=False)]
    if f_tipo_col.strip() and "TIPO DE ORDEN" in activas.columns:
        activas = activas[activas["TIPO DE ORDEN"].astype(str).str.contains(f_tipo_col.strip(), case=False, na=False)]
    if f_estado_col.strip():
        activas = activas[activas["ESTADO_ORDEN"].astype(str).str.upper() == f_estado_col.strip().upper()]
    if f_tecnico_col.strip() and "TECNICO_PRINCIPAL" in activas.columns:
        activas = activas[activas["TECNICO_PRINCIPAL"].astype(str).str.contains(f_tecnico_col.strip(), case=False, na=False)]

    if activas.empty:
        return html.Div("Sin datos con los filtros seleccionados.",
                        style={"color": C["gray"], "fontSize": "14px", "padding": "14px 0"})

    # Calcular días desde creación hasta hoy
    hoy = pd.Timestamp.now().normalize()
    if "FECHA / HORA CREACIÓN" in activas.columns:
        fecha_creacion = pd.to_datetime(activas["FECHA / HORA CREACIÓN"], errors="coerce")
        activas["DIAS_CREACION"] = (hoy - fecha_creacion).dt.days.clip(lower=0)
        activas["FECHA_STR"] = fecha_creacion.dt.strftime("%d/%m/%Y  %H:%M")
    else:
        activas["DIAS_CREACION"] = 0
        activas["FECHA_STR"] = "—"

    # Conservar PDF_ViewURL en el df para usarla en make_row, pero NO mostrarla como columna
    cols_show = ["OT_ID","TIPO DE ORDEN","ESTADO_ORDEN","FECHA_STR","TECNICO_PRINCIPAL","DIAS_CREACION"]
    cols_show = [c for c in cols_show if c in activas.columns or c in ["FECHA_STR","DIAS_CREACION"]]

    labels = {
        "OT_ID": "N° OT", "TIPO DE ORDEN": "Tipo de Orden",
        "ESTADO_ORDEN": "Estado", "FECHA_STR": "Fecha Creación",
        "TECNICO_PRINCIPAL": "Técnico Asignado", "DIAS_CREACION": "Días de Creación",
    }

    header = html.Tr([html.Th(labels.get(c, c)) for c in cols_show])

    def make_row(row):
        cells = []
        for c in cols_show:
            val = row.get(c, "—")
            if c == "ESTADO_ORDEN":
                s = str(val)
                cells.append(html.Td(html.Span(s, className="status-badge", style={
                    "background": STATUS_BG.get(s, "#F0F0F0"),
                    "color":      STATUS_COLORS.get(s, C["gray"]),
                })))
            elif c == "OT_ID":
                if pd.notna(val) and str(val) not in ("nan", ""):
                    ot_num = int(val)
                    # Obtener URL directamente de la columna PDF_ViewURL del Sheet
                    pdf_url = None
                    if "PDF_ViewURL" in row.index:
                        raw_url = row.get("PDF_ViewURL", "")
                        if pd.notna(raw_url) and str(raw_url).strip() not in ("", "nan", "None"):
                            pdf_url = str(raw_url).strip()
                    if pdf_url:
                        cells.append(html.Td(
                            html.A(
                                f"#{ot_num}",
                                href=pdf_url,
                                target="_blank",
                                title=f"Abrir PDF de OT #{ot_num} en Google Drive",
                                style={
                                    "fontWeight":     "700",
                                    "color":          C["blue"],
                                    "textDecoration": "none",
                                    "cursor":         "pointer",
                                    "padding":        "2px 6px",
                                    "borderRadius":   "4px",
                                    "border":         f"1px solid {C['blue']}",
                                    "transition":     "all 0.15s",
                                }
                            )
                        ))
                    else:
                        # Sin URL disponible: número sin enlace
                        cells.append(html.Td(
                            html.Span(
                                f"#{ot_num}",
                                title="Sin PDF disponible",
                                style={
                                    "fontWeight":     "700",
                                    "color":          C["gray"],
                                    "cursor":         "default",
                                    "padding":        "2px 6px",
                                    "borderRadius":   "4px",
                                    "border":         f"1px dashed {C['border']}",
                                }
                            )
                        ))
                else:
                    cells.append(html.Td("—", style={"fontWeight":"700","color":C["blue"]}))
            elif c == "DIAS_CREACION":
                dias = int(val) if pd.notna(val) else 0
                # Color por urgencia
                if dias > 30:   col_dias = C["red"]
                elif dias > 14: col_dias = C["orange"]
                elif dias > 7:  col_dias = C["yellow"]
                else:           col_dias = C["green"]
                cells.append(html.Td(
                    html.Span(f"{dias} días", style={
                        "fontWeight":   "700",
                        "color":        col_dias,
                        "background":   f"{col_dias}18",
                        "padding":      "2px 8px",
                        "borderRadius": "4px",
                    })
                ))
            else:
                s = str(val)
                cells.append(html.Td("—" if s in ("nan","NaT","None","") else s))
        return html.Tr(cells)

    rows = [make_row(row) for _, row in activas.iterrows()]

    total_row = html.Tr([
        html.Td(f"Total: {len(activas)} órdenes",
                colSpan=len(cols_show),
                style={"fontWeight":"600","color":C["text_dim"],"fontSize":"12px",
                       "paddingTop":"10px","textAlign":"right","borderTop":f"2px solid {C['border']}"}),
    ])

    return html.Table(
        [html.Thead(header), html.Tbody(rows + [total_row])],
        className="pbi-table",
    )






