@app.callback(
    Output("login-overlay",       "style"),
    Output("login-error",         "className"),
    Output("login-success-store", "data"),
    Input("login-btn",  "n_clicks"),
    Input("login-user", "n_submit"),
    Input("login-pass", "n_submit"),
    State("login-user", "value"),
    State("login-pass", "value"),
    State("login-success-store", "data"),
    prevent_initial_call=True,
)
def handle_login(n_btn, n_user, n_pass, user, password, login_count):
    user     = (user     or "").strip().lower()
    password = (password or "").strip()
    if USERS.get(user) == password:
        # Esperar a que la precarga en background esté lista (máx 0.5 s)
        _preload_done.wait(timeout=0.5)
        return {"display": "none"}, "login-error", (login_count or 0) + 1
    return {}, "login-error show", login_count



@app.callback(
    Output("mapa-ecuador-iframe",   "srcDoc"),
    Output("mapa-legend-panel",     "children"),
    Output("mapa-header-label",     "children"),
    FILTER_INPUTS,
)
def mapa_ecuador(tipo, estado, tecnico, cliente, start, end, *_):
    """
    Genera el SVG del mapa de Ecuador y la leyenda lateral.
    El SVG usa viewBox → se escala solo al tamaño del iframe (CSS flex).
    El botón fullscreen lo maneja un clientside_callback (JS puro).
    """
    dff = filter_df(tipo, estado, tecnico, cliente, start, end)

    EMPTY_SVG = (
        '<!DOCTYPE html><html><body style="margin:0;background:#EEF5FB;">'
        '<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"'
        ' style="width:100%;height:100%">'
        '<rect width="400" height="300" fill="#EEF5FB"/>'
        '<text x="200" y="155" text-anchor="middle"'
        ' font-family="Segoe UI,sans-serif" font-size="15" fill="#888">'
        'Sin datos geográficos disponibles</text>'
        '</svg></body></html>'
    )
    EMPTY_LEGEND = html.Div("Sin datos", style={"color":"#aaa","fontSize":"12px"})
    EMPTY_LABEL  = "0 órdenes en 0 provincias"

    if ECUADOR_GEO is None:
        err = (
            '<!DOCTYPE html><html><body style="margin:0;background:#FFF3CD;">'
            '<svg viewBox="0 0 400 80" xmlns="http://www.w3.org/2000/svg"'
            ' style="width:100%;height:100%">'
            '<text x="200" y="45" text-anchor="middle"'
            ' font-family="Segoe UI,sans-serif" font-size="13" fill="#856404">'
            '⚠ ecuador_provinces.json no encontrado</text>'
            '</svg></body></html>'
        )
        return err, EMPTY_LEGEND, EMPTY_LABEL

    # ── Resolver provincia por orden ─────────────────────────────
    if "PROVINCIA_GEO" in dff.columns and dff["PROVINCIA_GEO"].notna().any():
        prov_series = dff["PROVINCIA_GEO"]
    elif "PROVINCIA" in dff.columns:
        prov_series = (dff["PROVINCIA"].astype(str).str.strip().str.upper()
                       .map(PROV_TO_GEO))
    elif "CIUDAD_CLIENTE" in dff.columns:
        prov_series = (dff["CIUDAD_CLIENTE"].astype(str).str.strip().str.upper()
                       .map(CIUDAD_TO_GEO_PROV))
    else:
        return EMPTY_SVG, EMPTY_LEGEND, EMPTY_LABEL

    dff = dff.copy()
    dff["_PROV"] = prov_series
    dff_geo = dff[dff["_PROV"].notna()]

    if dff_geo.empty:
        return EMPTY_SVG, EMPTY_LEGEND, EMPTY_LABEL

    # ── Conteo ───────────────────────────────────────────────────
    total    = len(dff_geo)
    prov_cnt = dff_geo.groupby("_PROV").size().reset_index(name="N")
    prov_cnt["PCT"] = (prov_cnt["N"] / total * 100).round(1)
    P_DICT   = dict(zip(prov_cnt["_PROV"], prov_cnt["N"]))
    PCT_DICT = dict(zip(prov_cnt["_PROV"], prov_cnt["PCT"]))
    MAX_N    = prov_cnt["N"].max() if not prov_cnt.empty else 1

    # ── Paleta de azul ───────────────────────────────────────────
    def blue_fill(n):
        if n == 0:
            return "#DDEEFF"
        t = n / MAX_N
        r = round(168 - 168 * t)
        g = round(216 -  98 * t)
        b = round(240 -  46 * t)
        return f"rgb({r},{g},{b})"

    def txt_color(n):
        return "#FFFFFF" if (n / MAX_N) > 0.25 else "#00264D"

    # ── Proyección mercator simple → coordenadas SVG ─────────────
    # viewBox fijo 500×590; el SVG se escala al 100% del iframe por CSS
    W, H, PAD = 500, 590, 10
    LON0, LON1 =  -81.10, -75.10
    LAT0, LAT1 =    1.55,  -5.15

    def proj(lon, lat):
        x = PAD + (lon - LON0) / (LON1 - LON0) * (W - 2 * PAD)
        y = PAD + (LAT0 - lat) / (LAT0 - LAT1) * (H - 2 * PAD)
        return round(x, 2), round(y, 2)

    def ring_to_path(ring):
        if not ring:
            return ""
        sx, sy = proj(ring[0][0], ring[0][1])
        d = f"M{sx},{sy}"
        for p in ring[1:]:
            px, py = proj(p[0], p[1])
            d += f"L{px},{py}"
        return d + "Z"

    def feature_to_path(feat):
        gtype = feat["geometry"]["type"]
        if gtype == "Polygon":
            d = ring_to_path(feat["geometry"]["coordinates"][0])
            for hole in feat["geometry"]["coordinates"][1:]:
                d += ring_to_path(hole)
        else:
            d = ""
            for poly in feat["geometry"]["coordinates"]:
                d += ring_to_path(poly[0])
                for hole in poly[1:]:
                    d += ring_to_path(hole)
        return d

    def centroid(feat):
        gtype = feat["geometry"]["type"]
        if gtype == "MultiPolygon":
            pts = max(feat["geometry"]["coordinates"], key=lambda p: len(p[0]))[0]
        else:
            pts = feat["geometry"]["coordinates"][0]
        n   = len(pts)
        cx  = sum(p[0] for p in pts) / n
        cy  = sum(p[1] for p in pts) / n
        return proj(cx, cy)

    # ── Construir paths y labels SVG ─────────────────────────────
    paths_svg  = []
    labels_svg = []
    gal_feat   = None

    for feat in ECUADOR_GEO["features"]:
        name = feat["properties"]["name"]
        if name == "Galápagos":
            gal_feat = feat
            continue

        n    = P_DICT.get(name, 0)
        pct  = PCT_DICT.get(name, 0.0)
        fill = blue_fill(n)
        d    = feature_to_path(feat)
        tip  = f"{name}: {n} OT ({pct}%)" if n > 0 else f"{name}: sin órdenes"

        paths_svg.append(
            f'<path d="{d}" fill="{fill}" '
            f'stroke="#111111" stroke-width="0.85" stroke-linejoin="round">'
            f'<title>{tip}</title></path>'
        )

        cx, cy = centroid(feat)
        tc     = txt_color(n)
        short  = (name.replace(" de los Tsáchilas", "")
                      .replace("Zamora Chinchipe", "Z.Chinchipe")
                      .replace("Morona Santiago",  "M.Santiago"))
        short  = short if len(short) <= 11 else short[:10]

        if n > 0:
            labels_svg.append(
                f'<text x="{cx}" y="{cy-7}" text-anchor="middle" '
                f'font-family="Segoe UI,Arial,sans-serif" font-size="9" font-weight="700" '
                f'fill="{tc}">{short}</text>'
                f'<text x="{cx}" y="{cy+7}" text-anchor="middle" '
                f'font-family="Segoe UI,Arial,sans-serif" font-size="10.5" font-weight="900" '
                f'fill="{tc}">{n} · {pct}%</text>'
            )
        else:
            labels_svg.append(
                f'<text x="{cx}" y="{cy+3}" text-anchor="middle" '
                f'font-family="Segoe UI,Arial,sans-serif" font-size="7.5" font-weight="400" '
                f'fill="#6B8FAA">{short}</text>'
            )

    # ── Galápagos inset (esquina inferior izquierda) ─────────────
    IW, IH = 108, 68
    IX, IY = -80, H - IH - 38
    gal_n    = P_DICT.get("Galápagos", 0)
    gal_pct  = PCT_DICT.get("Galápagos", 0.0)
    gal_fill = blue_fill(gal_n)
    gal_tc   = txt_color(gal_n) if gal_n > 0 else "#7A9BB5"
    gal_svg  = ""

    if gal_feat:
        g_pts  = [p for poly in gal_feat["geometry"]["coordinates"] for p in poly[0]]
        g_lons = [p[0] for p in g_pts]
        g_lats = [p[1] for p in g_pts]
        GL0, GL1 = min(g_lons) - 0.4, max(g_lons) + 0.4
        GB0, GB1 = max(g_lats) + 0.4, min(g_lats) - 0.4

        def proj_gal(lon, lat):
            x = IX + (lon - GL0) / (GL1 - GL0) * IW
            y = IY + (GB0 - lat) / (GB0 - GB1) * IH
            return round(x, 2), round(y, 2)

        for poly in gal_feat["geometry"]["coordinates"]:
            ring = poly[0]
            sx, sy = proj_gal(ring[0][0], ring[0][1])
            d = f"M{sx},{sy}" + "".join(
                f"L{proj_gal(p[0],p[1])[0]},{proj_gal(p[0],p[1])[1]}"
                for p in ring[1:]
            ) + "Z"
            gal_svg += (
                f'<path d="{d}" fill="{gal_fill}" '
                f'stroke="#111111" stroke-width="0.85"/>'
            )

    gal_lbl = f"{gal_n} · {gal_pct}%" if gal_n > 0 else "sin órdenes"

    # ── HTML del iframe — SVG 100%×100% dentro del body ──────────
    # El <svg> usa viewBox fijo y preserveAspectRatio="xMidYMid meet"
    # → siempre llena el espacio disponible sin deformarse
    svg_doc = (
        '<!DOCTYPE html>'
        '<html><head><style>'
        '*{margin:0;padding:0;box-sizing:border-box}'
        'html,body{width:100%;height:100%;overflow:hidden;background:#D0E8F5}'
        '</style></head>'
        f'<body>'
        f'<svg viewBox="0 0 {W} {H}" xmlns="http://www.w3.org/2000/svg"'
        f'     preserveAspectRatio="xMidYMid meet"'
        f'     style="width:100%;height:100%;display:block;">'
        f'  <rect width="{W}" height="{H}" fill="#D0E8F5"/>'
        + "".join(paths_svg)
        + "".join(labels_svg)
        # Inset Galápagos
        + f'  <rect x="{IX-5}" y="{IY-5}" width="{IW+10}" height="{IH+34}" rx="4"'
          f'        fill="#EEF7FF" stroke="#111111" stroke-width="0.9"/>'
        + gal_svg
        + f'  <text x="{IX+IW//2}" y="{IY+IH+11}" text-anchor="middle"'
          f'        font-family="Segoe UI,Arial" font-size="8" font-weight="700" fill="#333">Galápagos</text>'
          f'  <text x="{IX+IW//2}" y="{IY+IH+24}" text-anchor="middle"'
          f'        font-family="Segoe UI,Arial" font-size="8.5" font-weight="900" fill="{gal_tc}">{gal_lbl}</text>'
        + '</svg></body></html>'
    )

    # ── Leyenda lateral ───────────────────────────────────────────
    legend_items = []
    for _, row in prov_cnt.sort_values("N", ascending=False).iterrows():
        fill = blue_fill(row["N"])
        legend_items.append(html.Div([
            html.Div(style={
                "width": "13px", "height": "13px", "borderRadius": "2px",
                "background": fill, "border": "1px solid #111111",
                "flexShrink": "0",
            }),
            html.Span(row["_PROV"], style={
                "fontSize": "12px", "fontWeight": "600", "color": "#252423",
                "flex": "1", "overflow": "hidden", "textOverflow": "ellipsis",
                "whiteSpace": "nowrap",
            }),
            html.Div([
                html.Span(f"{row['N']} OT", style={
                    "fontWeight": "700", "color": "#0078D4", "fontSize": "11px",
                }),
                html.Span(f" ({row['PCT']}%)", style={
                    "color": "#666", "fontSize": "11px",
                }),
            ]),
        ], style={
            "display": "flex", "alignItems": "center", "gap": "6px",
            "padding": "5px 8px", "borderRadius": "4px", "marginBottom": "4px",
            "background": "#F0F7FF", "border": "1px solid #D6EAF8",
        }))

    legend = html.Div([
        html.Div("PROVINCIAS CON ÓRDENES", style={
            "fontSize": "10px", "fontWeight": "700", "color": "#8A8886",
            "letterSpacing": "1.5px", "marginBottom": "10px",
        }),
        *legend_items,
        html.Div(style={"flex": "1"}),
        # Escala de color
        html.Div([
            html.Div(style={
                "height": "10px", "borderRadius": "3px", "marginBottom": "4px",
                "background": "linear-gradient(to right,#A8D8F0,#0078D4,#002D62)",
                "border": "1px solid #111111",
            }),
            html.Div([
                html.Span("Menos", style={"fontSize": "9px", "color": "#666"}),
                html.Span("Más órdenes", style={"fontSize": "9px", "color": "#666"}),
            ], style={"display": "flex", "justifyContent": "space-between"}),
        ], style={"marginTop": "auto", "paddingTop": "12px"}),
    ], style={"display": "flex", "flexDirection": "column", "height": "100%"})

    header_label = f"{total} órdenes en {len(prov_cnt)} provincia(s)"
    return svg_doc, legend, header_label




