@app.callback(Output("fig-clientes", "figure"), FILTER_INPUTS)
def fig_clientes(tipo, estado, tecnico, cliente, start, end, *_):
    dff = filter_df(tipo, estado, tecnico, cliente, start, end)

    if "NOMBRE_CLIENTE" not in dff.columns:
        return empty_fig("Sin datos de clientes (requiere join con Customer)")

    cnt = (
        dff["NOMBRE_CLIENTE"]
        .dropna()
        .astype(str)
        .str.strip()
        .replace("", pd.NA)
        .dropna()
        .value_counts()
        .reset_index()
    )
    cnt.columns = ["Cliente", "N"]
    cnt = cnt[cnt["Cliente"] != "nan"].copy()

    if cnt.empty:
        return empty_fig("Sin datos de clientes")

    # Ordenar mayor a menor (ya viene así de value_counts)
    # Invertir para que el mayor quede arriba en barra horizontal
    cnt = cnt.sort_values("N", ascending=True)

    # Truncar nombre largo
    cnt["ClienteLabel"] = cnt["Cliente"].apply(
        lambda x: x[:42] + "…" if len(x) > 42 else x
    )

    # Color degradado azul
    n_items  = len(cnt)
    max_val  = cnt["N"].max()

    # Colorscale continuo
    import numpy as np
    norm_vals = cnt["N"] / max_val
    colors = [
        f"rgba({int(0 + (0)*v)}, {int(120 - 60*v)}, {int(212 - 80*v)}, 0.88)"
        for v in norm_vals
    ]
    # Usar azules fijos según valor relativo
    def blue_shade(v):
        if v >= 0.80: return C["blue_dark"]
        if v >= 0.55: return C["blue"]
        if v >= 0.30: return "#2B88D8"
        if v >= 0.10: return "#71AFE5"
        return C["blue_light"]

    bar_colors = [blue_shade(v) for v in norm_vals]

    # Calcular altura dinámica basada en número de clientes
    height = max(380, min(1400, n_items * 48 + 80))

    fig = go.Figure(go.Bar(
        x=cnt["N"],
        y=cnt["ClienteLabel"],
        orientation="h",
        marker=dict(
            color=bar_colors,
            line=dict(color="white", width=0.8),
        ),
        text=[f"  {v}" for v in cnt["N"]],
        textposition="outside",
        textfont=dict(size=12, family="Segoe UI, sans-serif", color=C["text"]),
        customdata=cnt[["Cliente","N"]].values,
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Órdenes: <b>%{customdata[1]}</b><extra></extra>"
        ),
        cliponaxis=False,
    ))

    fig.update_layout(
        height=height,
        xaxis=dict(
            title="Número de Órdenes",
            tickfont=dict(size=12),
            gridcolor="#F0F0F0",
        ),
        yaxis=dict(
            tickfont=dict(size=12),
            automargin=True,
        ),
        showlegend=False,
        margin=dict(l=8, r=60, t=20, b=20),
        bargap=0.15,
    )
    return apply_theme(fig)

