# CALLBACKS — MODAL FULLSCREEN
# ══════════════════════════════════════════════════════════════════

# IDs de todos los gráficos disponibles
ALL_GRAPH_IDS = [
    "fig-estado", "fig-tipo",
    "fig-tec-ot", "fig-tec-estado",
    "fig-marcas", "fig-equipos",
    "fig-duracion", "fig-diasemana", "fig-iac-mensual", "fig-tec-duracion",
    "fig-clientes",
]

@app.callback(
    Output("modal-overlay", "className"),
    Output("modal-title",   "children"),
    Output("modal-graph",   "figure"),
    [Input({"type": "maximize-btn", "index": gid}, "n_clicks") for gid in ALL_GRAPH_IDS]
    + [Input("modal-close", "n_clicks")],
    [State(gid, "figure") for gid in ALL_GRAPH_IDS],
    prevent_initial_call=True,
)
def toggle_modal(*args):
    n_graphs  = len(ALL_GRAPH_IDS)
    btn_clicks = args[:n_graphs + 1]   # n_clicks de cada botón maximize + close
    figures    = args[n_graphs + 1:]   # figures actuales de cada gráfico

    triggered = ctx.triggered_id

    # Cerrar modal
    if triggered == "modal-close" or triggered is None:
        return "modal-overlay", "", go.Figure()

    # Abrir modal: identificar qué botón se pulsó
    if isinstance(triggered, dict) and triggered.get("type") == "maximize-btn":
        graph_id = triggered["index"]
        if graph_id in ALL_GRAPH_IDS:
            idx = ALL_GRAPH_IDS.index(graph_id)
            fig_data = figures[idx]

            # Reconstruir figura desde dict con fondo blanco y márgenes amplios
            if fig_data:
                fig = go.Figure(fig_data)
                fig.update_layout(
                    paper_bgcolor="white",
                    plot_bgcolor="white",
                    margin=dict(l=40, r=40, t=30, b=40),
                    font=dict(size=15),
                    height=None,  # se adapta al contenedor
                )
            else:
                fig = go.Figure()

            # Título legible del gráfico
            titles = {
                "fig-estado":       "Estado de Órdenes",
                "fig-tipo":         "Tipo de Orden",
                "fig-tec-ot":       "Órdenes por Técnico",
                "fig-tec-estado":   "Estado por Técnico",
                "fig-marcas":       "Top Marcas por Cantidad",
                "fig-equipos":      "Tipos de Equipo",
                "fig-duracion":     "Distribución Duración (días)",
                "fig-diasemana":    "OT por Día de la Semana",
                "fig-iac-mensual":    "IAC Mensual — Índice de Atención al Cliente (%)",
                "fig-clientes":      "Órdenes por Cliente — Ranking Total",
                "fig-tec-duracion": "Duración Promedio / Técnico",
            }
            title = titles.get(graph_id, graph_id)
            return "modal-overlay open", title, fig

    return "modal-overlay", "", go.Figure()

# ══════════════════════════════════════════════════════════════════
# ══════════════════════════════════════════════════════════════════
# CLIENTSIDE CALLBACK — FULLSCREEN DEL MAPA
# Único método garantizado en Dash para ejecutar JS en el cliente.
# Usa CSS overlay (position:fixed) como mecanismo principal —
# siempre funciona sin importar si el navegador permite
# requestFullscreen (que requiere interacción directa en algunos).
# ══════════════════════════════════════════════════════════════════
app.clientside_callback(
    """
    function(n) {
        if (!n) return window.dash_clientside.no_update;

        var card = document.getElementById('mapa-card');
        var btn  = document.getElementById('mapa-fullscreen-btn');
        if (!card) return window.dash_clientside.no_update;

        var already = card.getAttribute('data-fs') === '1';

        if (!already) {
            // ── Entrar en pantalla completa ──────────────────────
            // Intentar API nativa (Chrome/Edge/Firefox)
            var req = card.requestFullscreen
                   || card.webkitRequestFullscreen
                   || card.mozRequestFullScreen
                   || card.msRequestFullscreen;
            if (req) { try { req.call(card); } catch(e) {} }

            // CSS overlay — siempre funciona como fallback
            card.style.cssText = [
                'position:fixed!important',
                'top:0!important',
                'left:0!important',
                'width:100vw!important',
                'height:100vh!important',
                'max-height:100vh!important',
                'z-index:99998!important',
                'border-radius:0!important',
                'margin:0!important',
                'box-shadow:none!important',
            ].join(';');
            document.body.style.overflow = 'hidden';
            card.setAttribute('data-fs', '1');

            // Actualizar botón
            if (btn) {
                var icon = btn.querySelector('.fs-icon');
                var lbl  = btn.querySelector('.fs-label');
                if (icon) icon.textContent = '\u2921';
                if (lbl)  lbl.textContent  = '  Salir';
                btn.style.setProperty('background',   '#0078D4', 'important');
                btn.style.setProperty('color',        'white',   'important');
                btn.style.setProperty('border-color', '#0078D4', 'important');
            }

        } else {
            // ── Salir de pantalla completa ───────────────────────
            var ex = document.exitFullscreen
                  || document.webkitExitFullscreen
                  || document.mozCancelFullScreen
                  || document.msExitFullscreen;
            if (ex) { try { ex.call(document); } catch(e) {} }

            card.style.cssText = '';
            document.body.style.overflow = '';
            card.setAttribute('data-fs', '0');

            if (btn) {
                var icon2 = btn.querySelector('.fs-icon');
                var lbl2  = btn.querySelector('.fs-label');
                if (icon2) icon2.textContent = '\u2922';
                if (lbl2)  lbl2.textContent  = '  Pantalla completa';
                btn.style.removeProperty('background');
                btn.style.removeProperty('color');
                btn.style.removeProperty('border-color');
            }
        }

        return window.dash_clientside.no_update;
    }
    """,
    Output("mapa-fs-store", "data"),
    Input("mapa-fullscreen-btn", "n_clicks"),
    prevent_initial_call=True,
)


# ══════════════════════════════════════════════════════════════════
# RUTA FLASK — Servir PDFs de órdenes
# Carpeta esperada: ./ordenes/OT_00123.pdf  (mismo directorio que este script)
# ══════════════════════════════════════════════════════════════════
from flask import send_from_directory, abort

PDF_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), "ordenes")

@app.server.route("/ordenes/<path:filename>")
def serve_pdf(filename):
    """Sirve el PDF de la orden si existe, de lo contrario 404."""
    pdf_path = os.path.join(PDF_FOLDER, filename)
    if not os.path.isfile(pdf_path):
        # Devolver página amigable de 404
        return (
            f"<html><body style='font-family:Segoe UI;padding:40px'>"
            f"<h2 style='color:#D13438'>&#x26A0; PDF no encontrado</h2>"
            f"<p>El archivo <b>{filename}</b> no existe en la carpeta <code>ordenes/</code>.</p>"
            f"<p>Asegúrate de guardar los PDFs con el formato <b>OT_00001.pdf</b></p>"
            f"<a href='javascript:window.close()' style='color:#0078D4'>Cerrar pestaña</a>"
            f"</body></html>",
            404,
        )
    return send_from_directory(PDF_FOLDER, filename, mimetype="application/pdf")


server = app.server  # expuesto para gunicorn

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 8050))
    app.run(host="0.0.0.0", port=port, debug=False)
